import subprocess, json

# 1. Define tools the agent can use
TOOLS = {
    "read_file": lambda path: open(path).read(),
    "write_file": lambda path, content: open(path, "w").write(content),
    "run_shell": lambda cmd: subprocess.run(
        cmd, shell=True, capture_output=True, text=True, timeout=30
    ).stdout,
}

# 2. Tool dispatcher
def execute_tool(tool_call, tools):
    fn = tools[tool_call["name"]]
    return fn(**tool_call["arguments"])

# 3. The agent loop
def agent_loop(task, tools, max_steps=20):
    messages = [{"role": "user", "content": task}]
    for step in range(max_steps):
        response = call_llm(messages)
        if response["done"]:
            return response["content"]
        result = execute_tool(response["tool_call"], tools)
        messages.append({"role": "assistant", "content": json.dumps(response["tool_call"])})
        messages.append({"role": "tool", "content": result})
    return "Max steps reached"

class AgentMemory:
    def __init__(self, max_tokens=100_000):
        self.messages = []
        self.scratchpad = {}
        self.max_tokens = max_tokens

    def add(self, message):
        self.messages.append(message)
        if self.token_count() > self.max_tokens:
            self._compress()

    def _compress(self):
        mid = len(self.messages) // 2
        old = self.messages[:mid]
        summary = call_llm([{"role": "user",
            "content": "Summarize: " + str(old)}])
        self.messages = [
            {"role": "system", "content": summary}
        ] + self.messages[mid:]

    def token_count(self):
        return sum(len(m["content"]) // 4 for m in self.messages)

